import{_ as d}from"./BfenRalM.js";import{_ as s}from"./CBm65aLf.js";import{i,v as b,e as r,h as t,f as n}from"./CFpVv8Xf.js";import{_ as v}from"./DlAUqK2U.js";const c={class:"page-container"},l=i({__name:"about",setup(u){const o=a=>{window.location.href=a.url};return(a,e)=>(b(),r("div",c,[t(d,{title:"About Us",subtitle:"Learn more about Photo Grid Overlay"}),e[0]||(e[0]=n('<main class="page-content" data-v-dab9bb72><div class="content-section" data-v-dab9bb72><h2 data-v-dab9bb72>About Photo Grid Overlay</h2><section data-v-dab9bb72><h3 data-v-dab9bb72>Our Mission</h3><p data-v-dab9bb72>Photo Grid Overlay is a free online tool designed to help artists, designers, and photography enthusiasts add customizable grid lines to their images. Whether you&#39;re sketching from a reference photo, creating Instagram grid layouts, or planning compositions, our tool provides the precision you need.</p></section><section data-v-dab9bb72><h3 data-v-dab9bb72>Why Choose Us?</h3><div class="features-list" data-v-dab9bb72><div class="feature-item" data-v-dab9bb72><div class="feature-icon" data-v-dab9bb72>🔒</div><div class="feature-content" data-v-dab9bb72><h4 data-v-dab9bb72>Privacy First</h4><p data-v-dab9bb72>All processing happens locally in your browser. Your images never leave your device.</p></div></div><div class="feature-item" data-v-dab9bb72><div class="feature-icon" data-v-dab9bb72>🎨</div><div class="feature-content" data-v-dab9bb72><h4 data-v-dab9bb72>Customizable</h4><p data-v-dab9bb72>Adjust columns, rows, colors, line width, and opacity to suit your needs.</p></div></div><div class="feature-item" data-v-dab9bb72><div class="feature-icon" data-v-dab9bb72>⚡</div><div class="feature-content" data-v-dab9bb72><h4 data-v-dab9bb72>Fast &amp; Free</h4><p data-v-dab9bb72>No registration required. Start using immediately, completely free.</p></div></div><div class="feature-item" data-v-dab9bb72><div class="feature-icon" data-v-dab9bb72>📱</div><div class="feature-content" data-v-dab9bb72><h4 data-v-dab9bb72>Mobile Friendly</h4><p data-v-dab9bb72>Works seamlessly on desktop, tablet, and mobile devices.</p></div></div></div></section><section data-v-dab9bb72><h3 data-v-dab9bb72>Our Story</h3><p data-v-dab9bb72>Photo Grid Overlay was created out of a need for a simple, privacy-focused tool for artists. As artists ourselves, we struggled to find a grid tool that didn&#39;t require uploading images to servers or paying for subscriptions. So we built one.</p><p data-v-dab9bb72>What started as a personal project has grown into a tool used by thousands of creatives worldwide. We&#39;re committed to keeping it free, private, and continuously improving based on user feedback.</p></section><section data-v-dab9bb72><h3 data-v-dab9bb72>Contact Us</h3><p data-v-dab9bb72>We&#39;d love to hear from you! Whether you have feedback, suggestions, or just want to say hello, you can reach us at hello@photogridoverlay.com.</p></section></div></main>',1)),t(s,{company:"Photo Grid App",onNavigate:o})]))}}),g=v(l,[["__scopeId","data-v-dab9bb72"]]);export{g as default};
